const input = $input.first().json;
const elements = input.elements || [];
const results = [];

for (const el of elements) {
    const tags = el.tags || {};

    // Koordinaten finden (entweder direkt oder im Center-Punkt bei Gebäuden)
    const lat = el.lat || (el.center ? el.center.lat : null);
    const lon = el.lon || (el.center ? el.center.lon : null);

    // Wir extrahieren die Daten
    results.push({
        json: {
            state_code: (tags["addr:state"] || "N/A").toUpperCase(), // In Großbuchstaben für saubere Sortierung
            city: tags["addr:city"] || "N/A",
            zip: tags["addr:postcode"] || "N/A",
            street: tags["addr:street"] || "N/A",
            house_number: tags["addr:housenumber"] || "",
            name: tags.name || "ALDI",
            lat: lat,
            lon: lon
        }
    });
}

// 1. Filtern: Nur Einträge mit echten Adressdaten behalten
const filteredResults = results.filter(r => r.json.street !== "N/A" || r.json.city !== "N/A");

// 2. Sortieren: Alphabetisch nach Bundesstaat (state)
filteredResults.sort((a, b) => {
    if (a.json.state_code < b.json.state_code) return -1;
    if (a.json.state_code > b.json.state_code) return 1;

    // Optional: Innerhalb des Staates nach Stadt sortieren
    if (a.json.city < b.json.city) return -1;
    if (a.json.city > b.json.city) return 1;

    return 0;
});

return filteredResults;

const states = {
    "AL": "Alabama", "AK": "Alaska", "AZ": "Arizona", "AR": "Arkansas", "CA": "California",
    "CO": "Colorado", "CT": "Connecticut", "DE": "Delaware", "FL": "Florida", "GA": "Georgia",
    "HI": "Hawaii", "ID": "Idaho", "IL": "Illinois", "IN": "Indiana", "IA": "Iowa",
    "KS": "Kansas", "KY": "Kentucky", "LA": "Louisiana", "ME": "Maine", "MD": "Maryland",
    "MA": "Massachusetts", "MI": "Michigan", "MN": "Minnesota", "MS": "Mississippi", "MO": "Missouri",
    "MT": "Montana", "NE": "Nebraska", "NV": "Nevada", "NH": "New Hampshire", "NJ": "New Jersey",
    "NM": "New Mexico", "NY": "New York", "NC": "North Carolina", "ND": "North Dakota", "OH": "Ohio",
    "OK": "Oklahoma", "OR": "Oregon", "PA": "Pennsylvania", "RI": "Rhode Island", "SC": "South Carolina",
    "SD": "South Dakota", "TN": "Tennessee", "TX": "Texas", "UT": "Utah", "VT": "Vermont",
    "VA": "Virginia", "WA": "Washington", "WV": "West Virginia", "WI": "Wisconsin", "WY": "Wyoming",
    "DC": "District of Columbia"
};

// Umwandlung in ein n8n-kompatibles Array für Iterationen
return Object.entries(states).map(([code, name]) => {
  return {
    json: {
      state_code: code,
      state_name: name
    }
  };
});

return [
  { json: { zip: "60601" } }, // Chicago
  { json: { zip: "32801" } }, // Orlando
  { json: { zip: "90001" } }  // Los Angeles
];

const results = [];

// Wir prüfen, ob die Daten direkt im Item liegen oder im response.locations Array
const stores = $input.all()[0].json.response.locations || [];

const dayMap = {
  1: 'Mo', 2: 'Di', 3: 'Mi', 4: 'Do', 5: 'Fr', 6: 'Sa', 7: 'So'
};

for (const store of stores) {
  // Wir bauen die Öffnungszeiten in einen lesbaren String um
  let hoursFormatted = "N/A";
  if (store.openingHours && Array.isArray(store.openingHours)) {
    hoursFormatted = store.openingHours
      .map(h => `${dayMap[h.dayOfWeek]}: ${h.from1}-${h.to1}`)
      .join(' | ');
  }

  results.push({
    json: {
      store_id: store.id,
      internal_id: store.identifier, // z.B. F100
      name: store.name,
      address: store.streetAndNumber,
      zip: store.zip,
      city: store.city,
      state: store.province,
      phone: store.phone,
      latitude: store.lat,
      longitude: store.lng,
      status: store.openNow ? "Geöffnet" : "Geschlossen",
      opening_hours_summary: hoursFormatted,
      google_maps_url: `https://www.google.com/maps?q=${store.lat},${store.lng}`
    }
  });
}

return results;

// Dieser Modus ("Run Once for All Items") sammelt alle 52 Antworten ein
const allItems = $input.all();
const finalTable = [];

const dayMap = {
  1: 'Mo', 2: 'Di', 3: 'Mi', 4: 'Do', 5: 'Fr', 6: 'Sa', 7: 'So'
};

for (const item of allItems) {
  // Wir schauen in das response-Objekt jeder Stadt-Antwort
  const stores = item.json.response?.locations;

  if (stores && Array.isArray(stores)) {
    for (const store of stores) {

      // Öffnungszeiten-String bauen
      let hoursSummary = "N/A";
      if (store.openingHours && Array.isArray(store.openingHours)) {
        hoursSummary = store.openingHours
          .map(h => {
            const day = dayMap[h.dayOfWeek] || `Tag ${h.dayOfWeek}`;
            return `${day}: ${h.from1}-${h.to1}`;
          })
          .join(' | ');
      }

      // n8n Format: Jedes Ergebnis muss in ein { json: { ... } } Objekt
      finalTable.push({
        json: {
          store_id: store.id,
          internal_id: store.identifier || "N/A",
          name: store.name,
          address: store.streetAndNumber,
          zip: store.zip,
          city: store.city,
          state: store.province,
          lat: store.lat,
          lng: store.lng,
          phone: store.phone,
          status: store.openNow ? "Geöffnet" : "Geschlossen",
          opening_hours: hoursSummary,
          google_maps_url: `https://www.google.com/maps/search/?api=1&query=${store.lat},${store.lng}`
        }
      });
    }
  }
}

// Gibt die komplette, flache Liste aller Filialen zurück
return finalTable;

return [
  {
    json: {
      "aldi-adressen": [
          {
            "store_id": 2640,
            "full_address": "630 Fellsway Medford, MA 02155",
            "lat": 42.40709,
            "lon": -71.0836
          },
          {
            "store_id": 2641,
            "full_address": "100 Independence Way Danvers, MA 01923",
            "lat": 42.552845,
            "lon": -70.939445
          },
          {
            "store_id": 2642,
            "full_address": "70 Boston Providence Tpke East Walpole, MA 02032",
            "lat": 42.155506,
            "lon": -71.201674
          }
      ]
    }
  }
];

const result = [];

for (const item of $input.all()) {
    // Greife auf das gesamte JSON-Objekt des aktuellen Items zu
    const data = item.json;

    // Fallback: Setze den short-Namen standardmäßig auf den vollen Namen
    let providerShort = data.Provider;

    // Wenn " Holding Company" im String existiert, schneiden wir alles danach ab
    if (providerShort && providerShort.includes(" Holding Company")) {
        providerShort = providerShort.split(" Holding Company")[0].trim();
    }

    // Füge das neue Feld dem bestehenden JSON hinzu
    data.Provider_short = providerShort;

    result.push({
        json: data
    });
}

return result;

const result = [];

// Gehe durch alle eingehenden Items
for (const item of $input.all()) {

    // Greife auf die Adresse und das Providers-Array der aktuellen JSON-Struktur zu
    const address = item.json.address;
    const store_id = item.json.store_id
    const providersArray = item.json.providers;

    // Prüfen, ob das Array existiert und nicht leer ist
    if (!providersArray || !Array.isArray(providersArray) || providersArray.length === 0) continue;

    // Der Markdown-String liegt im ersten Element des providers-Arrays
    const tableString = providersArray[0];

    // Wenn es kein String ist, überspringen
    if (typeof tableString !== 'string') continue;

    // String in einzelne Zeilen aufteilen
    const rows = tableString.split('\n');

    // Wir starten bei Index 2, um die Kopfzeile und Formatierungszeile zu überspringen
    for (let i = 2; i < rows.length; i++) {
        const row = rows[i].trim();
        if (!row) continue; // Leere Zeilen ignorieren

        // Zeile bei '|' trennen, Whitespaces entfernen UND den Text ersetzen
        const columns = row.split('|').map(col => {
            let text = col.trim();
            // Ersetzt jedes Vorkommen des Satzes durch "yes "
            return text.replaceAll("Click to filter map by provider", "yes ");
        });

        // Nutzdaten liegen auf den Indizes 1 bis 5
        if (columns.length >= 6) {
            result.push({
                json: {
                    // Hier wird die Adresse aus dem Haupt-JSON eingefügt
                    "address": address,
                    "store_id": store_id,
                    // Die restlichen Daten werden aus den Spalten der Tabelle gezogen
                    "Provider": columns[1], 
                    "3G": columns[2],
                    "4G LTE": columns[3],
                    "5G-NR": columns[4],
                    "Requests": columns[5]
                }
            });
        }
    }
}

return result;
